# CoAP message types
COAP_TYPE_CON = 0
COAP_TYPE_NON = 1
COAP_TYPE_ACK = 2
COAP_TYPE_RST = 3

# CoAP method codes
COAP_GET = 1
COAP_POST = 2
COAP_PUT = 3
COAP_DELETE = 4

# CoAP response codes
COAP_CONTENT = 69  # 2.05
COAP_CHANGED = 68  # 2.04
COAP_NOT_FOUND = 132  # 4.04
COAP_METHOD_NOT_ALLOWED = 133  # 4.05
COAP_BAD_REQUEST = 128  # 4.00

# CoAP option numbers
COAP_OPTION_URI_PATH = 11
COAP_OPTION_CONTENT_FORMAT = 12

# Content formats
COAP_CONTENT_FORMAT_TEXT = 0
COAP_CONTENT_FORMAT_JSON = 50

class CoapMessage:
    def __init__(self):
        self.version = 1
        self.msg_type = COAP_TYPE_CON
        self.token_length = 0
        self.code = 0
        self.msg_id = 0
        self.token = b''
        self.options = []
        self.payload = b''
    
    @staticmethod
    def parse(data):
        if len(data) < 4:
            return None
        
        msg = CoapMessage()
        
        # Parse header
        byte0 = data[0]
        msg.version = (byte0 >> 6) & 0x03
        msg.msg_type = (byte0 >> 4) & 0x03
        msg.token_length = byte0 & 0x0F
        
        msg.code = data[1]
        msg.msg_id = struct.unpack('!H', data[2:4])[0]
        
        offset = 4
        
        # Parse token
        if msg.token_length > 0:
            msg.token = data[offset:offset + msg.token_length]
            offset += msg.token_length
        
        # Parse options
        option_number = 0
        while offset < len(data):
            if data[offset] == 0xFF:
                offset += 1
                break
            
            delta = (data[offset] >> 4) & 0x0F
            length = data[offset] & 0x0F
            offset += 1
            
            if delta == 13:
                delta = data[offset] + 13
                offset += 1
            elif delta == 14:
                delta = struct.unpack('!H', data[offset:offset+2])[0] + 269
                offset += 2
            
            if length == 13:
                length = data[offset] + 13
                offset += 1
            elif length == 14:
                length = struct.unpack('!H', data[offset:offset+2])[0] + 269
                offset += 2
            
            option_number += delta
            option_value = data[offset:offset + length]
            offset += length
            
            msg.options.append((option_number, option_value))
        
        # Parse payload
        if offset < len(data):
            msg.payload = data[offset:]
        
        return msg
    
    def encode(self):
        # Build header
        byte0 = (self.version << 6) | (self.msg_type << 4) | self.token_length
        header = struct.pack('!BBH', byte0, self.code, self.msg_id)
        
        result = bytearray(header)
        result.extend(self.token)
        
        # Encode options
        prev_option_number = 0
        for option_number, option_value in sorted(self.options):
            delta = option_number - prev_option_number
            length = len(option_value)
            
            delta_ext = b''
            if delta < 13:
                delta_nibble = delta
            elif delta < 269:
                delta_nibble = 13
                delta_ext = bytes([delta - 13])
            else:
                delta_nibble = 14
                delta_ext = struct.pack('!H', delta - 269)
            
            length_ext = b''
            if length < 13:
                length_nibble = length
            elif length < 269:
                length_nibble = 13
                length_ext = bytes([length - 13])
            else:
                length_nibble = 14
                length_ext = struct.pack('!H', length - 269)
            
            result.append((delta_nibble << 4) | length_nibble)
            result.extend(delta_ext)
            result.extend(length_ext)
            result.extend(option_value)
            
            prev_option_number = option_number
        
        # Add payload marker and payload
        if self.payload:
            result.append(0xFF)
            result.extend(self.payload)
        
        return bytes(result)

class CoapServer:
    def __init__(self, port=5683):
        self.port = port
        self.sock = None
        self.resources = {}
        self.light_state = False
        
        # Register default resources
        self.register_resource('/sensors/temp', self.handle_temp, ['GET'])
        self.register_resource('/actuators/light', self.handle_light, ['GET', 'PUT'])
    
    def register_resource(self, path, handler, methods):
        self.resources[path] = {'handler': handler, 'methods': methods}
    
    def handle_temp(self, method, payload):
        if method == COAP_GET:
            # Simulate temperature reading
            temp = 20.0 + random.uniform(-5, 5)
            return COAP_CONTENT, '{"temperature": %.2f}' % temp
        return COAP_METHOD_NOT_ALLOWED, ''
    
    def handle_light(self, method, payload):
        if method == COAP_GET:
            state = "on" if self.light_state else "off"
            return COAP_CONTENT, '{"light": "%s"}' % state
        elif method == COAP_PUT:
            try:
                if b'on' in payload:
                    self.light_state = True
                elif b'off' in payload:
                    self.light_state = False
                return COAP_CHANGED, '{"result": "ok"}'
            except:
                return COAP_BAD_REQUEST, ''
        return COAP_METHOD_NOT_ALLOWED, ''
    
    def extract_uri_path(self, options):
        path_parts = []
        for opt_num, opt_val in options:
            if opt_num == COAP_OPTION_URI_PATH:
                path_parts.append(opt_val.decode('utf-8'))
        if path_parts:
            return '/' + '/'.join(path_parts)
        return '/'
    
    def create_response(self, request, code, payload):
        response = CoapMessage()
        response.version = 1
        
        if request.msg_type == COAP_TYPE_CON:
            response.msg_type = COAP_TYPE_ACK
        else:
            response.msg_type = COAP_TYPE_NON
        
        response.code = code
        response.msg_id = request.msg_id
        response.token = request.token
        response.token_length = len(request.token)
        
        if payload:
            response.options.append((COAP_OPTION_CONTENT_FORMAT, bytes([COAP_CONTENT_FORMAT_JSON])))
            response.payload = payload.encode('utf-8') if isinstance(payload, str) else payload
        
        return response
    
    def handle_request(self, request):
        uri_path = self.extract_uri_path(request.options)
        
        if uri_path not in self.resources:
            return self.create_response(request, COAP_NOT_FOUND, '')
        
        resource = self.resources[uri_path]
        
        method_code = request.code
        method_name = {COAP_GET: 'GET', COAP_PUT: 'PUT', COAP_POST: 'POST', COAP_DELETE: 'DELETE'}.get(method_code)
        
        if method_name not in resource['methods']:
            return self.create_response(request, COAP_METHOD_NOT_ALLOWED, '')
        
        try:
            response_code, payload = resource['handler'](method_code, request.payload)
            return self.create_response(request, response_code, payload)
        except Exception as e:
            print('Error handling request:', e)
            return self.create_response(request, COAP_BAD_REQUEST, '')
    
    def start(self):
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind(('0.0.0.0', self.port))
        self.sock.setblocking(False)
        
        print('CoAP server listening on port', self.port)
        
        while True:
            try:
                data, addr = self.sock.recvfrom(1024)
                request = CoapMessage.parse(data)
                
                if request:
                    response = self.handle_request(request)
                    response_data = response.encode()
                    self.sock.sendto(response_data, addr)
            except OSError:
                time.sleep(0.01)
            except Exception as e:
                print('Error:', e)
                time.sleep(0.01)
    
    def stop(self):
        if self.sock:
            self.sock.close()

